from flask import Flask, request, jsonify
from datetime import datetime, timedelta

app = Flask(__name__)

# Assume database layer is implemented separately
from database import db

# Initialize the database connection
db.connect()

# Define a function to calculate progress
def calculate_progress(todo_list):
    total_items = len(todo_list)
    completed_items = sum(1 for item in todo_list if item['completed'])
    return (completed_items / total_items) * 100 if total_items > 0 else 0

# Define a function to get due or overdue tasks
def get_due_tasks(todo_list):
    due_tasks = []
    for item in todo_list:
        if item['due_date'] and item['due_date'] <= datetime.now():
            due_tasks.append(item)
    return due_tasks

# Define a function to get upcoming tasks
def get_upcoming_tasks(todo_list):
    upcoming_tasks = []
    for item in todo_list:
        if item['due_date'] and item['due_date'] > datetime.now() and item['due_date'] <= datetime.now() + timedelta(days=7):
            upcoming_tasks.append(item)
    return upcoming_tasks

