from flask import Flask, request, jsonify

app = Flask(__name__)

# Sample in-memory data store
data_store = {
    "products": [
        {"id": 1, "name": "Product 1", "price": 10.99},
        {"id": 2, "name": "Product 2", "price": 9.99},
        {"id": 3, "name": "Product 3", "price": 12.99}
    ],
    "orders": []
}

# API endpoint to get all products
@app.route('/products', methods=['GET'])
def get_products():
    return jsonify(data_store["products"])

# API endpoint to get a product by id
@app.route('/products/<int:product_id>', methods=['GET'])
def get_product(product_id):
    product = next((p for p in data_store["products"] if p["id"] == product_id), None)
    if product is None:
        return jsonify({"error": "Product not found"}), 404
    return jsonify(product)

# API endpoint to create a new order
@app.route('/orders', methods=['POST'])
def create_order():
    order_data = request.json
    if "product_id" not in order_data or "quantity" not in order_data:
        return jsonify({"error": "Invalid order data"}), 400
    product_id = order_data["product_id"]
    quantity = order_data["quantity"]
    product = next((p for p in data_store["products"] if p["id"] == product_id), None)
    if product is None:
        return jsonify({"error": "Product not found"}), 404
    order = {
        "id": len(data_store["orders"]) + 1,
        "product_id": product_id,
        "quantity": quantity,
        "total": product["price"] * quantity
    }
    data_store["orders"].append(order)
    return jsonify(order), 201

# API endpoint to get all orders
@app.route('/orders', methods=['GET'])
def get_orders():
    return jsonify(data_store["orders"])

