class WebQueryAPI:
    def __init__(self, base_url, api_key):
        self.base_url = base_url
        self.api_key = api_key

    def get(self, endpoint, params=None):
        import requests
        headers = {'Authorization': f'Bearer {self.api_key}'}
        response = requests.get(f'{self.base_url}{endpoint}', headers=headers, params=params)
        return response.json()

    def post(self, endpoint, data):
        import requests
        headers = {'Authorization': f'Bearer {self.api_key}', 'Content-Type': 'application/json'}
        response = requests.post(f'{self.base_url}{endpoint}', headers=headers, json=data)
        return response.json()

    def put(self, endpoint, data):
        import requests
        headers = {'Authorization': f'Bearer {self.api_key}', 'Content-Type': 'application/json'}
        response = requests.put(f'{self.base_url}{endpoint}', headers=headers, json=data)
        return response.json()

    def delete(self, endpoint):
        import requests
        headers = {'Authorization': f'Bearer {self.api_key}'}
        response = requests.delete(f'{self.base_url}{endpoint}', headers=headers)
        return response.json()

class QueryManager:
    def __init__(self, api):
        self.api = api

    def query(self, query_string):
        endpoint = '/query'
        params = {'q': query_string}
        return self.api.get(endpoint, params)

    def create_index(self, index_name):
        endpoint = '/indexes'
        data = {'name': index_name}
        return self.api.post(endpoint, data)

    def delete_index(self, index_name):
        endpoint = f'/indexes/{index_name}'
        return self.api.delete(endpoint)

    def update_document(self, index_name, document_id, data):
        endpoint = f'/indexes/{index_name}/documents/{document_id}'
        return self.api.put(endpoint, data)

    def search(self, index_name, query_string):
        endpoint = f'/indexes/{index_name}/query'
        params = {'q': query_string}
        return self.api.get(endpoint, params)

def main():
    api_key = 'your_api_key_here'
    base_url = 'https://your_api_url_here'
    api = WebQueryAPI(base_url, api_key)
    query_manager = QueryManager(api)
    print(query_manager.query('example query'))
    print(query_manager.create_index('example_index'))
    print(query_manager.delete_index('example_index'))
    print(query_manager.update_document('example_index', 'example_document', {'field': 'value'}))
    print(query_manager.search('example_index', 'example query'))

if __name__ == '__main__':
    main()

